questionvariables.text:
/* 1. Define randomized dimensions */
r: 2 + rand(4);          /* Radius: 2 to 5 m */
h_cyl: 6 + rand(6);      /* Height: 6 to 11 m */

/* 2. Volume of Cylinder: V1 = pi * r^2 * h */
V_cyl: %pi * r^2 * h_cyl;

/* 3. Volume of Hemisphere: V2 = 2/3 * pi * r^3 */
V_hemi: (2/3) * %pi * r^3;

/* 4. Total Volume and Teacher Answer */
total_v: V_cyl + V_hemi;
ta: total_v;

/* 5. Variables for the worked solution display */
r2: r^2;
r3: r^3;

/* 6. JSXGraph scaling */
r_draw: r/2;
h_draw: h_cyl/2;
